const values = $.steps.readLeads.response.values || [];
let leadsText = '';
let leads = [];

values.forEach((row, i) => {
  if (i === 0) return;
  const lead = { name: row[0] || '', email: row[1] || '', company: row[2] || '', role: row[3] || '', source: row[4] || '', notes: row[5] || '' };
  leads.push(lead);
  leadsText += (i) + '. ' + lead.name + ' | ' + lead.email + ' | ' + lead.company + ' | ' + lead.role + ' | Source: ' + lead.source + ' | Notes: ' + lead.notes + '\n';
});

return { leads, leadsText, leadCount: leads.length };

const data = $.steps.parseLeads.output;
const criteria = $.input.qualificationCriteria;
const company = $.input.companyName || 'Our Company';

const prompt = 'You are a sales qualification specialist. Score and qualify these leads based on the ideal customer profile.

IDEAL CUSTOMER PROFILE:
' + criteria + '

LEADS TO QUALIFY:
' + data.leadsText + '

For each lead, provide a qualification score and personalized follow-up email.

Return ONLY valid JSON:
{
  "qualifiedLeads": [
    {
      "leadNumber": 1,
      "name": "lead name",
      "email": "email",
      "score": 85,
      "qualification": "Hot/Warm/Cold/Disqualified",
      "reasons": ["reason for score"],
      "followUpEmail": {
        "subject": "personalized email subject",
        "body": "short personalized follow-up email body (2-3 paragraphs)"
      },
      "nextAction": "suggested next step"
    }
  ],
  "summary": {
    "totalLeads": 0,
    "hot": 0,
    "warm": 0,
    "cold": 0,
    "disqualified": 0,
    "averageScore": 0
  },
  "insights": ["pattern or insight about the lead batch"]
}';

return { prompt };

let raw = $.steps.aiQualify.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { qualifiedLeads: [], summary: { totalLeads: 0 }, insights: [raw.slice(0, 200)] }; }

const leads = $.steps.parseAI.output.qualifiedLeads || [];
const qualified = leads.filter(l => l.qualification === 'Hot' || l.qualification === 'Warm');
return { qualified };

const ai = $.steps.parseAI.output;
const leads = ai.qualifiedLeads || [];
const summary = ai.summary || {};
const rows = leads.map(l => [
  l.name || '',
  l.email || '',
  l.score || 0,
  l.qualification || '',
  (l.reasons || []).join('; '),
  l.nextAction || '',
  new Date().toISOString().split('T')[0]
]);

const slackText = 'Lead qualification complete: ' + (summary.totalLeads || leads.length) + ' leads scored | Hot: ' + (summary.hot || 0) + ' | Warm: ' + (summary.warm || 0) + ' | Cold: ' + (summary.cold || 0) + ' | Avg Score: ' + (summary.averageScore || 0);
return { rows, slackText };
